package jetbrains.mps.tool.environment;

/*Generated by MPS */

import org.apache.log4j.Logger;
import org.apache.log4j.LogManager;
import java.util.Set;
import jetbrains.mps.tool.common.PluginData;
import jetbrains.mps.internal.collections.runtime.SetSequence;
import java.util.LinkedHashSet;
import java.util.Map;
import java.io.File;
import jetbrains.mps.internal.collections.runtime.MapSequence;
import java.util.LinkedHashMap;
import org.jetbrains.annotations.NotNull;
import java.util.Collections;
import jetbrains.mps.util.annotation.ToRemove;
import jetbrains.mps.tool.common.PathManager;

/**
 * Represents a configuration options list for an environment, used a Builder pattern
 * 
 * @see jetbrains.mps.tool.environment.Environment 
 */
public class EnvironmentConfig {
  private static final Logger LOG = LogManager.getLogger(EnvironmentConfig.class);
  private final Set<PluginData> myPlugins = SetSequence.fromSet(new LinkedHashSet<PluginData>());
  private final Map<String, File> myMacros = MapSequence.fromMap(new LinkedHashMap<String, File>(16, (float) 0.75, false));
  private final Set<String> myLibs = SetSequence.fromSet(new LinkedHashSet<String>());
  private final Set<String> myPluginClassPath = SetSequence.fromSet(new LinkedHashSet<String>());

  /**
   * due to the support in IDEA we are able to support it in MPS
   * fixme implement with MpsEnv
   */
  private boolean myCreatePluginClassLoaders = true;

  private EnvironmentConfig() {
  }

  @NotNull
  public Set<PluginData> getPlugins() {
    return SetSequence.fromSet(myPlugins).asUnmodifiable();
  }

  public Map<String, File> getMacros() {
    return Collections.unmodifiableMap(myMacros);
  }

  public Set<String> getLibs() {
    return SetSequence.fromSet(myLibs).asUnmodifiable();
  }

  public boolean doesCreatePluginClassLoaders() {
    return myCreatePluginClassLoaders;
  }

  /**
   * 
   * @deprecated unused, no reason to keep
   */
  @Deprecated
  @ToRemove(version = 2019.1)
  public Set<String> getPluginClassPath() {
    return myPluginClassPath;
  }

  public EnvironmentConfig addPlugin(String path, String id) {
    File pluginLocation = new File(path);

    // this is a compatibility code needed to support relative paths, also see doc comment for PluginData 
    // todo get rid of it 
    final File localPluginsFolder = new File(PathManager.getPluginsPath());
    final File preinstalledPluginFolder = new File(jetbrains.mps.util.PathManager.getPreInstalledPluginsPath());
    // XXX we don't support plugins distributed as .zip files here, only as folders 
    if (!(new File(pluginLocation, PlatformPlugins.PLUGIN_DESCRIPTOR_LOCATION).exists())) {
      pluginLocation = new File(localPluginsFolder, path);
      if (!(new File(pluginLocation, PlatformPlugins.PLUGIN_DESCRIPTOR_LOCATION).exists())) {
        pluginLocation = new File(preinstalledPluginFolder, path);
        if (!(new File(pluginLocation, PlatformPlugins.PLUGIN_DESCRIPTOR_LOCATION).exists())) {
          if (LOG.isDebugEnabled()) {
            LOG.debug(String.format("No platform plugin descriptor (plugin.xml) detected under %s", path));
          }
          SetSequence.fromSet(myPlugins).addElement(new PluginData(path, id));
          return this;
        }
      }
    }

    SetSequence.fromSet(myPlugins).addElement(new PluginData(pluginLocation.getAbsolutePath(), id));
    return this;
  }

  public EnvironmentConfig addMacro(String macroName, File macroValue) {
    MapSequence.fromMap(myMacros).put(macroName, macroValue);
    return this;
  }

  public EnvironmentConfig addLib(String libPath) {
    SetSequence.fromSet(myLibs).addElement(libPath);
    return this;
  }

  public EnvironmentConfig setCreatePluginClassLoaders(boolean value) {
    myCreatePluginClassLoaders = value;
    return this;
  }

  /**
   * 
   * @deprecated unused value, just drop uses
   */
  @Deprecated
  @ToRemove(version = 2019.1)
  public void addPluginClassPath(String cp) {
    SetSequence.fromSet(myPluginClassPath).addElement(cp);
  }

  public EnvironmentConfig withDefaultSamples() {
    return addMacro("samples_home", new File(System.getProperty("user.dir"), "samples"));
  }

  public EnvironmentConfig withDefaultPlugins() {
    addPlugin("mps-testing", "jetbrains.mps.testing");
    addPlugin("mpsmake", "jetbrains.mps.ide.make");
    return withCorePlugin();
  }

  public EnvironmentConfig withVcsPlugin() {
    return addPlugin("vcs", "jetbrains.mps.vcs").withGit4IdeaPlugin();
  }

  public EnvironmentConfig withCorePlugin() {
    return addPlugin("mps-core", "jetbrains.mps.core");
  }

  public EnvironmentConfig withGit4IdeaPlugin() {
    return addPlugin("git4idea", "Git4Idea");
  }

  public EnvironmentConfig withBuildPlugin() {
    return addPlugin("mps-build", "jetbrains.mps.build");
  }

  public EnvironmentConfig withJavaPlugin() {
    return addPlugin("mps-java-workbench", "jetbrains.mps.ide.java").addPlugin("mpsjava", "jetbrains.mps.ide.java.platform");
  }

  public EnvironmentConfig withMigrationPlugin() {
    // migration plugin depends on modelchecker, add both 
    return addPlugin("modelchecker", "jetbrains.mps.ide.modelchecker").addPlugin("migration", "jetbrains.mps.ide.migration.workbench");
  }

  public EnvironmentConfig withBootstrapLibraries() {
    for (String path : jetbrains.mps.util.PathManager.getBootstrapPaths()) {
      addLib(path);
    }
    addLib(jetbrains.mps.util.PathManager.getLanguagesPath());
    return this;
  }

  public EnvironmentConfig withWorkbenchPath() {
    addLib(jetbrains.mps.util.PathManager.getWorkbenchPath());
    return this;
  }

  public static EnvironmentConfig defaultConfig() {
    return new EnvironmentConfig().withDefaultSamples().withDefaultPlugins().withBootstrapLibraries().withWorkbenchPath();
  }

  /**
   * 
   * @return EnvironmentConfig with no specified plugins. At the time of writing it meant that the platform will load all the plugins. Note that one needs to provide a proper class path.
   */
  public static EnvironmentConfig defaultConfigNoPluginsSpecified() {
    EnvironmentConfig defaultConf = defaultConfig();
    return defaultConf;
  }

  /**
   * fixme: currently the repository within the 'empty environment' is inconsistent (mps-core plugin is needed),
   * so use defaultConfig
   */
  public static EnvironmentConfig emptyConfig() {
    return new EnvironmentConfig();
  }
}
